// Generate end card: dark bg + subscribe CTA
// Short-form: 3s, Long-form: 5-8s
const { execSync } = require('child_process');
const input = $input.first().json;
const topicId = input.topic_id;
const isShort = input.short_form || false;
const duration = isShort ? 3 : 6;
const outputPath = `/tmp/production/endcard_${topicId}.mp4`;

// Create dark background end card with fade
// Uses a solid dark frame with subscribe text
try {
  const cmd = `ffmpeg -y -f lavfi -i "color=c=0x0A0A1A:s=${isShort ? '1080x1920' : '1920x1080'}:d=${duration}" ` +
    `-vf "drawtext=text='Subscribe for more':fontsize=48:fontcolor=white:x=(w-tw)/2:y=(h-th)/2-40,` +
    `drawtext=text='Like & Share':fontsize=32:fontcolor=0xFBBF24:x=(w-tw)/2:y=(h-th)/2+30,` +
    `fade=in:st=0:d=0.5,fade=out:st=${duration - 0.5}:d=0.5" ` +
    `-c:v libx264 -pix_fmt yuv420p -preset medium -crf 18 "${outputPath}"`;
  execSync(cmd, { timeout: 30000 });
} catch (e) {
  return [{ json: { success: false, error: 'End card generation failed: ' + e.message, topic_id: topicId } }];
}

return [{ json: {
  success: true,
  topic_id: topicId,
  endcard_path: outputPath,
  duration: duration,
  is_short_form: isShort,
} }];
